bool is_accept[STATE_COUNT] = {false,false,false,false,false,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true,true};

int token_id[STATE_COUNT] = {-1,-1,-1,-1,-1,100,100,101,102,201,202,203,204,205,207,208,209,210,211,212,213,214,215,216,217,218,219,220,221,222,223};

string token_name[STATE_COUNT] = {"","","","","","num100","num100","ID101","comment102","plus201","minus202","times203","over204","mod205","lt207","lte208","gt209","gte210","eq211","neq212","assign213","semi214","comma215","inc216","dec217","lparen218","rparen219","lbrack220","rbrack221","lbrace222","rbrace223"};

int get_keyword_id(const string& lexeme) {
    if(lexeme == "do") return 110;
    if(lexeme == "else") return 103;
    if(lexeme == "float") return 106;
    if(lexeme == "for") return 112;
    if(lexeme == "if") return 104;
    if(lexeme == "int") return 105;
    if(lexeme == "real") return 107;
    if(lexeme == "return") return 108;
    if(lexeme == "void") return 109;
    if(lexeme == "while") return 111;
    return -1;
}


int main(int argc, char** argv) {
    if (argc < 2) {
        cerr << "Usage: " << argv[0] << " <source_file>" << endl;
        return 1;
    }
    
    ifstream in(argv[1]);
    if (!in) {
        cerr << "Error opening file " << argv[1] << endl;
        return 1;
    }
    
    string code((istreambuf_iterator<char>(in)), istreambuf_iterator<char>());
    size_t pos = 0;
    
    string out_name = string(argv[1]);
    size_t dot_pos = out_name.find_last_of('.');
    if(dot_pos != string::npos) out_name = out_name.substr(0, dot_pos);
    out_name += ".lex";
    
    ofstream out(out_name);
    
    while(pos < code.length()) {
        // ================= 【核心修复：顶层双重预处理】 =================
        bool pre_processed = true;
        while (pre_processed && pos < code.length()) {
            pre_processed = false;

            // 1. 无条件跳过空白符
            while (pos < code.length() && isspace(static_cast<unsigned char>(code[pos]))) {
                pos++;
                pre_processed = true;
            }

            // 2. 识别并静默跳过 MiniC 语言的行注释 (以 // 开头)
            if (pos + 1 < code.length() && code[pos] == '/' && code[pos + 1] == '/') {
                pos += 2; // 略过 "//"
                while (pos < code.length() && code[pos] != '\n' && code[pos] != '\r') {
                    pos++; // 吞掉整行注释内容
                }
                pre_processed = true;
                continue;
            }

            // 3. 识别并静默跳过 TINY 语言的花括号块注释 (以 { 开头)
            if (pos < code.length() && code[pos] == '{') {
                // 注意：在 MiniC 中，{ 和 } 是合法的界符(lbrace222, rbrace223)。
                // 只有当你要兼容纯 TINY 语言的注释时，才启用下面这段块注释吞噬逻辑。
                // 如果当前跑的是纯 MiniC 系统测试，请保持这段逻辑处于注释/禁用状态。
                /*
                size_t j = pos + 1;
                while (j < code.length() && code[j] != '}') {
                    j++;
                }
                if (j < code.length() && code[j] == '}') {
                    pos = j + 1; // 成功吞掉整段 TINY 块注释
                    pre_processed = true;
                    continue;
                }
                */
            }
        }
        
        if (pos >= code.length()) break;
        // =============================================================
        
        int state = 2;
        int last_accept_state = -1;
        size_t last_accept_pos = pos;
        
        // 2. 最长匹配前向探查
        size_t i = pos;
        while(i < code.length()) {
            unsigned char c = code[i];
            if (c >= 256) break; 
            
            int next_state = transition[state][c];
            
            // 【回归纯粹】：这里不需要任何对注释的硬编码拦截
            if(next_state == -1) {
                break; // 普通 Token 转移失败，交给后续结算
            }
            
            state = next_state;
            i++;
            if(is_accept[state]) {
                last_accept_state = state;
                last_accept_pos = i;
            }
        }
        
        // 3. 匹配结果分流处理
        if (last_accept_state != -1) {
            string lexeme = code.substr(pos, last_accept_pos - pos);
            pos = last_accept_pos; // 推进全局主指针
            
            // 【无需判断】：注释早已在顶层被滤除，能走到这里的绝不可能是注释
            int final_token_id = token_id[last_accept_state];
            int kw_id = get_keyword_id(lexeme);
            
            if(kw_id != -1) {
                final_token_id = kw_id;
            }
            
            // 4. 标准输出规范
            if (kw_id != -1) {
                out << final_token_id << " ";
                cout << final_token_id << " ";
            } else if (token_name[last_accept_state].find("ID") != string::npos || 
                       token_name[last_accept_state].find("id") != string::npos) {
                out << final_token_id << " \"" << lexeme << "\" ";
                cout << final_token_id << " \"" << lexeme << "\" ";
            } else if (token_name[last_accept_state].find("num") != string::npos || 
                       token_name[last_accept_state].find("NUM") != string::npos || 
                       token_name[last_accept_state].find("digit") != string::npos) {
                out << final_token_id << " " << lexeme << " ";
                cout << final_token_id << " " << lexeme << " ";
            } else {
                out << final_token_id << " ";
                cout << final_token_id << " ";
            }
        } else {
            // 5. 健壮的错误恢复
            pos++;
        }
    }
    return 0;
}
